SELECT SUM(iron_prod) AS total_iron_production
FROM production_metrics
WHERE operator_id = 'specific_operator_id';

SELECT mine_id, SUM(reserve_ironcontent) AS total_iron_content
FROM reserves
GROUP BY mine_id;

SELECT date, iron_prod, iron_metallics
FROM market_data
WHERE date = 'specific_date';

SELECT plant_id, AVG(iron_metallics) AS average_iron_metallics
FROM production_metrics
GROUP BY plant_id;
